import { ref } from 'vue'
import { useStore } from 'vuex'
import { updateNickname } from '@/api/user'
import { showToast } from '@/components/ToastMessage'

export function useNickname() {
  const store = useStore()
  const value = ref('')
  const loading = ref(false)

  const handleUpdate = async () => {
    if (!value.value.trim() || value.value.trim().length < 2) {
      showToast('昵称长度至少2个字符', 'error')
      return false
    }

    loading.value = true
    try {
      console.log('Updating nickname:', value.value)
      await updateNickname(value.value)
      await store.dispatch('fetchUserInfo')
      showToast('昵称修改成功', 'success')
      return true
    } catch (error) {
      console.error('Update nickname error:', error)
      showToast(error.message || '修改失败', 'error')
      return false
    } finally {
      loading.value = false
      console.log('Loading state after update:', loading.value)
    }
  }

  const reset = () => {
    value.value = ''
    loading.value = false
  }

  return {
    value,
    loading,
    handleUpdate,
    reset
  }
}
